const items = $input.all();
if (!items || items.length === 0 || !items[0].json.id) return [];
return items;

var opp = $json;
var prompt = 'You are scoring federal opportunities for Georgetown Defense Analytics (GDA/Envision Innovative Solutions).

';
prompt += 'GDA PROFILE:
';
prompt += '- Mid-tier defense IT/engineering services firm ($100M revenue target)
';
prompt += '- 3 OUs: Envision (C5ISR/SETA/engineering at APG), PD Systems (training/simulation), Riverstone (cybersecurity)
';
prompt += '- Core work: SETA, systems engineering, software dev, IT support, training/sim, cyber operations, intelligence analysis
';
prompt += '- Target customers: SOCOM, TRADOC/PEO STRI, AFC, INSCOM, CYBERCOM, DISA, C5ISR Center, CECOM
';
prompt += '- GDA is LARGE business on most revenue NAICS (SBA 5yr avg $54.1M)
';
prompt += '- Active contracts: IEW&S SETA (recompete), STEP, PM MC Product Support, C5ISR Sustaining Eng, DEVCOM Eng Support
';
prompt += '- IDIQs: RS3 SB (prime), MDA SHIELD (sub), targeting OASIS+, SEWP VI

';
prompt += 'GDA DOES NOT DO: facilities maintenance, construction, plumbing, HVAC, painting, elevator repair, janitorial, food service, vehicle maintenance, grounds keeping, roofing, physical security guards, laundry, fuel delivery, medical clinical services, or hardware/parts procurement.

';
prompt += 'OPPORTUNITY:
';
prompt += 'Title: ' + (opp.opp_title || 'Unknown') + '
';
prompt += 'Agency: ' + (opp.agency || 'Unknown') + '
';
prompt += 'NAICS: ' + (opp.naics_code || 'Unknown') + '
';
prompt += 'Set-Aside: ' + (opp.set_aside || 'None') + '
';
prompt += 'Value: $' + ((opp.estimated_value || 0) / 1000000).toFixed(1) + 'M
';
prompt += 'Deadline: ' + (opp.response_deadline || 'TBD') + '
';
prompt += 'Location: ' + (opp.place_of_performance || 'Unknown') + '

';
prompt += 'SCORING (0-100):
';
prompt += '- Domain Fit (40pts): Is this IT/engineering/SETA/cyber/training work GDA actually does? Score 0 if facilities/construction/hardware.
';
prompt += '- Competitive Position (30pts): Target agency overlap? GDA past performance? Set-aside fit (GDA is LARGE)?
';
prompt += '- Urgency (15pts): Is deadline actionable? Is this a recompete GDA should track?
';
prompt += '- Strategic Value (15pts): Revenue size fit ($5M-$100M sweet spot)? Grows GDA footprint in target agencies?

';
prompt += 'LABELS: PURSUE (80+, actively bid), EVALUATE (60-79, worth tracking), MONITOR (40-59, watch only), PASS (<40, not GDA work)
';
prompt += 'If the work is NOT IT/engineering/SETA/cyber/training — score it PASS regardless of other factors.

';
prompt += 'Respond ONLY with JSON (no markdown, no backticks):
{
  "gda_score": 0-100,
  "gda_label": "PURSUE|EVALUATE|MONITOR|PASS",
  "ai_analysis": "2-3 sentence analysis of why this does or does not fit GDA",
  "assigned_ou": "Envision|PD Systems|Riverstone|Cross-OU",
  "sb_qualified": "Yes|No|Partial",
  "likely_competitors": "comma-separated top 3 likely competitors"
}';

return [{ json: { opp_id: opp.id, opp_title: opp.opp_title, prompt: prompt } }];

parameters.jsonBody:
={{ JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 500,
  messages: [{ role: 'user', content: $json.prompt }]
}) }}

